"""
Parameterized generator for GH1009_spaCy_12486.

Source PR:    https://github.com/explosion/spaCy/pull/12486
Source Issue: N/A

Seed varies: renames 'add_pipe' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1009_spaCy_12486'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1009_spaCy_12486'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('add_pipe', 'add_pipe' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1009_spaCy_12486',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'explosion/spaCy',
                "pr_number": 12486,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/explosion/spaCy/pull/12486",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'spacy/pipeline/spancat.py': 'from typing import List, Dict, Callable, Tuple, Optional, Iterable, Any, cast, Union\nfrom dataclasses import dataclass\nfrom thinc.api import Config, Model, get_current_ops, set_dropout_rate, Ops\nfrom thinc.api import Optimizer\nfrom thinc.types import Ragged, Ints2d, Floats2d\n\nimport numpy\n\nfrom ..compat import Protocol, runtime_checkable\nfrom ..scorer import Scorer\nfrom ..language import Language\nfrom .trainable_pipe import TrainablePipe\nfrom ..tokens import Doc, SpanGroup, Span\nfrom ..vocab import Vocab\nfrom ..training import Example, validate_examples\nfrom ..errors import Errors\nfrom ..util import registry\n\n\nspancat_default_config = """\n[model]\n@architectures = "spacy.SpanCategorizer.v1"\nscorer = {"@layers": "spacy.LinearLogistic.v1"}\n\n[model.reducer]\n@layers = spacy.mean_max_reducer.v1\nhidden_size = 128\n\n[model.tok2vec]\n@architectures = "spacy.Tok2Vec.v2"\n\n[model.tok2vec.embed]\n@architectures = "spacy.MultiHashEmbed.v2"\nwidth = 96\nrows = [5000, 2000, 1000, 1000]\nattrs = ["ORTH", "PREFIX", "SUFFIX", "SHAPE"]\ninclude_static_vectors = false\n\n[model.tok2vec.encode]\n@architectures = "spacy.MaxoutWindowEncoder.v2"\nwidth = ${model.tok2vec.embed.width}\nwindow_size = 1\nmaxout_pieces = 3\ndepth = 4\n"""\n\nspancat_singlelabel_default_config = """\n[model]\n@architectures = "spacy.SpanCategorizer.v1"\nscorer = {"@layers": "Softmax.v2"}\n\n[model.reducer]\n@layers = spacy.mean_max_reducer.v1\nhidden_size = 128\n\n[model.tok2vec]\n@architectures = "spacy.Tok2Vec.v2"\n[model.tok2vec.embed]\n@architectures = "spacy.MultiHashEmbed.v1"\nwidth = 96\nrows = [5000, 1000, 2500, 1000]\nattrs = ["NORM", "PREFIX", "SUFFIX", "SHAPE"]\ninclude_static_vectors = false\n\n[model.tok2vec.encode]\n@architectures = "spacy.MaxoutWindowEncoder.v2"\nwidth = ${model.tok2vec.embed.width}\nwindow_size = 1\nmaxout_pieces = 3\ndepth = 4\n"""\n\nDEFAULT_SPANCAT_MODEL = Config().from_str(spancat_default_config)["model"]\nDEFAULT_SPANCAT_SINGLELABEL_MODEL = Config().from_str(\n    spancat_singlelabel_default_config\n)["model"]\n\n\n@runtime_checkable\nclass Suggester(Protocol):\n    def __call__(self, docs: Iterable[Doc], *, ops: Optional[Ops] = None) -> Ragged:\n        ...\n\n\n@registry.misc("spacy.ngram_suggester.v1")\ndef build_ngram_suggester(sizes: List[int]) -> Suggester:\n    """Suggest all spans of the given lengths. Spans are returned as a ragged\n    array of integers. The array has two columns, indicating the start and end\n    position."""\n\n    def ngram_suggester(docs: Iterable[Doc], *, ops: Optional[Ops] = None) -> Ragged:\n        if ops is None:\n            ops = get_current_ops()\n        spans = []\n        lengths = []\n        for doc in docs:\n            starts = ops.xp.arange(len(doc), dtype="i")\n            starts = starts.reshape((-1, 1))\n            length = 0\n            for size in sizes:\n                if size <= len(doc):\n                    starts_size = starts[: len(doc) - (size - 1)]\n                    spans.append(ops.xp.hstack((starts_size, starts_size + size)))\n                    length += spans[-1].shape[0]\n                if spans:\n                    assert spans[-1].ndim == 2, spans[-1].shape\n            lengths.append(length)\n        lengths_array = ops.asarray1i(lengths)\n        if len(spans) > 0:\n            output = Ragged(ops.xp.vstack(spans), lengths_array)\n        else:\n            output = Ragged(ops.xp.zeros((0, 0), dtype="i"), lengths_array)\n\n        assert output.dataXd.ndim == 2\n        return output\n\n    return ngram_suggester\n\n\n@registry.misc("spacy.ngram_range_suggester.v1")\ndef build_ngram_range_suggester(min_size: int, max_size: int) -> Suggester:\n    """Suggest all spans of the given lengths between a given min and max value - both inclusive.\n    Spans are returned as a ragged array of integers. The array has two columns,\n    indicating the start and end position."""\n    sizes = list(range(min_size, max_size + 1))\n    return build_ngram_suggester(sizes)\n\n\n@Language.factory(\n    "spancat",\n    assigns=["doc.spans"],\n    default_config={\n        "threshold": 0.5,\n        "spans_key": "sc",\n        "max_positive": None,\n        "model": DEFAULT_SPANCAT_MODEL,\n        "suggester": {"@misc": "spacy.ngram_suggester.v1", "sizes": [1, 2, 3]},\n        "scorer": {"@scorers": "spacy.spancat_scorer.v1"},\n    },\n    default_score_weights={"spans_sc_f": 1.0, "spans_sc_p": 0.0, "spans_sc_r": 0.0},\n)\ndef make_spancat(\n    nlp: Language,\n    name: str,\n    suggester: Suggester,\n    model: Model[Tuple[List[Doc], Ragged], Floats2d],\n    spans_key: str,\n    scorer: Optional[Callable],\n    threshold: float,\n    max_positive: Optional[int],\n) -> "SpanCategorizer":\n    """Create a SpanCategorizer component and configure it for multi-label\n    classification to be able to assign multiple labels for each span.\n    The span categorizer consists of two\n    parts: a suggester function that proposes candidate spans, and a labeller\n    model that predicts one or more labels for each span.\n\n    name (str): The component instance name, used to add entries to the\n        losses during training.\n    suggester (Callable[[Iterable[Doc], Optional[Ops]], Ragged]): A function that suggests spans.\n        Spans are returned as a ragged array with two integer columns, for the\n        start and end positions.\n    model (Model[Tuple[List[Doc], Ragged], Floats2d]): A model instance that\n        is given a list of documents and (start, end) indices representing\n        candidate span offsets. The model predicts a probability for each category\n        for each span.\n    spans_key (str): Key of the doc.spans dict to save the spans under. During\n        initialization and training, the component will look for spans on the\n        reference document under the same key.\n    scorer (Optional[Callable]): The scoring method. Defaults to\n        Scorer.score_spans for the Doc.spans[spans_key] with overlapping\n        spans allowed.\n    threshold (float): Minimum probability to consider a prediction positive.\n        Spans with a positive prediction will be saved on the Doc. Defaults to\n        0.5.\n    max_positive (Optional[int]): Maximum number of labels to consider positive\n        per span. Defaults to None, indicating no limit.\n    """\n    return SpanCategorizer(\n        nlp.vocab,\n        model=model,\n        suggester=suggester,\n        name=name,\n        spans_key=spans_key,\n        negative_weight=None,\n        allow_overlap=True,\n        max_positive=max_positive,\n        threshold=threshold,\n        scorer=scorer,\n        add_negative_label=False,\n    )\n\n\n@Language.factory(\n    "spancat_singlelabel",\n    assigns=["doc.spans"],\n    default_config={\n        "spans_key": "sc",\n        "model": DEFAULT_SPANCAT_SINGLELABEL_MODEL,\n        "negative_weight": 1.0,\n        "suggester": {"@misc": "spacy.ngram_suggester.v1", "sizes": [1, 2, 3]},\n        "scorer": {"@scorers": "spacy.spancat_scorer.v1"},\n        "allow_overlap": True,\n    },\n    default_score_weights={"spans_sc_f": 1.0, "spans_sc_p": 0.0, "spans_sc_r": 0.0},\n)\ndef make_spancat_singlelabel(\n    nlp: Language,\n    name: str,\n    suggester: Suggester,\n    model: Model[Tuple[List[Doc], Ragged], Floats2d],\n    spans_key: str,\n    negative_weight: float,\n    allow_overlap: bool,\n    scorer: Optional[Callable],\n) -> "SpanCategorizer":\n    """Create a SpanCategorizer component and configure it for multi-class\n    classification. With this configuration each span can get at most one\n    label. The span categorizer consists of two\n    parts: a suggester function that proposes candidate spans, and a labeller\n    model that predicts one or more labels for each span.\n\n    name (str): The component instance name, used to add entries to the\n        losses during training.\n    suggester (Callable[[Iterable[Doc], Optional[Ops]], Ragged]): A function that suggests spans.\n        Spans are returned as a ragged array with two integer columns, for the\n        start and end positions.\n    model (Model[Tuple[List[Doc], Ragged], Floats2d]): A model instance that\n        is given a list of documents and (start, end) indices representing\n        candidate span offsets. The model predicts a probability for each category\n        for each span.\n    spans_key (str): Key of the doc.spans dict to save the spans under. During\n        initialization and training, the component will look for spans on the\n        reference document under the same key.\n    scorer (Optional[Callable]): The scoring method. Defaults to\n        Scorer.score_spans for the Doc.spans[spans_key] with overlapping\n        spans allowed.\n    negative_weight (float): Multiplier for the loss terms.\n        Can be used to downweight the negative samples if there are too many.\n    allow_overlap (bool): If True the data is assumed to contain overlapping spans.\n        Otherwise it produces non-overlapping spans greedily prioritizing\n        higher assigned label scores.\n    """\n    return SpanCategorizer(\n        nlp.vocab,\n        model=model,\n        suggester=suggester,\n        name=name,\n        spans_key=spans_key,\n        negative_weight=negative_weight,\n        allow_overlap=allow_overlap,\n        max_positive=1,\n        add_negative_label=True,\n        threshold=None,\n        scorer=scorer,\n    )\n\n\ndef spancat_score(examples: Iterable[Example], **kwargs) -> Dict[str, Any]:\n    kwargs = dict(kwargs)\n    attr_prefix = "spans_"\n    key = kwargs["spans_key"]\n    kwargs.setdefault("attr", f"{attr_prefix}{key}")\n    kwargs.setdefault("allow_overlap", True)\n    kwargs.setdefault(\n        "getter", lambda doc, key: doc.spans.get(key[len(attr_prefix) :], [])\n    )\n    kwargs.setdefault("has_annotation", lambda doc: key in doc.spans)\n    return Scorer.score_spans(examples, **kwargs)\n\n\n@registry.scorers("spacy.spancat_scorer.v1")\ndef make_spancat_scorer():\n    return spancat_score\n\n\n@dataclass\nclass _Intervals:\n    """\n    Helper class to avoid storing overlapping spans.\n    """\n\n    def __init__(self):\n        self.ranges = set()\n\n    def add(self, i, j):\n        for e in range(i, j):\n            self.ranges.add(e)\n\n    def __contains__(self, rang):\n        i, j = rang\n        for e in range(i, j):\n            if e in self.ranges:\n                return True\n        return False\n\n\nclass SpanCategorizer(TrainablePipe):\n    """Pipeline component to label spans of text.\n\n    DOCS: https://spacy.io/api/spancategorizer\n    """\n\n    def __init__(\n        self,\n        vocab: Vocab,\n        model: Model[Tuple[List[Doc], Ragged], Floats2d],\n        suggester: Suggester,\n        name: str = "spancat",\n        *,\n        add_negative_label: bool = False,\n        spans_key: str = "spans",\n        negative_weight: Optional[float] = 1.0,\n        allow_overlap: Optional[bool] = True,\n        max_positive: Optional[int] = None,\n        threshold: Optional[float] = 0.5,\n        scorer: Optional[Callable] = spancat_score,\n    ) -> None:\n        """Initialize the multi-label or multi-class span categorizer.\n\n        vocab (Vocab): The shared vocabulary.\n        model (thinc.api.Model): The Thinc Model powering the pipeline component.\n            For multi-class classification (single label per span) we recommend\n            using a Softmax classifier as a the final layer, while for multi-label\n            classification (multiple possible labels per span) we recommend Logistic.\n        suggester (Callable[[Iterable[Doc], Optional[Ops]], Ragged]): A function that suggests spans.\n            Spans are returned as a ragged array with two integer columns, for the\n            start and end positions.\n        name (str): The component instance name, used to add entries to the\n            losses during training.\n        spans_key (str): Key of the Doc.spans dict to save the spans under.\n            During initialization and training, the component will look for\n            spans on the reference document under the same key. Defaults to\n            `"spans"`.\n        add_negative_label (bool): Learn to predict a special \'negative_label\'\n            when a Span is not annotated.\n        threshold (Optional[float]): Minimum probability to consider a prediction\n            positive. Defaults to 0.5. Spans with a positive prediction will be saved\n            on the Doc.\n        max_positive (Optional[int]): Maximum number of labels to consider\n            positive per span. Defaults to None, indicating no limit.\n        negative_weight (float): Multiplier for the loss terms.\n            Can be used to downweight the negative samples if there are too many\n            when add_negative_label is True. Otherwise its unused.\n        allow_overlap (bool): If True the data is assumed to contain overlapping spans.\n            Otherwise it produces non-overlapping spans greedily prioritizing\n            higher assigned label scores. Only used when max_positive is 1.\n        scorer (Optional[Callable]): The scoring method. Defaults to\n            Scorer.score_spans for the Doc.spans[spans_key] with overlapping\n            spans allowed.\n\n        DOCS: https://spacy.io/api/spancategorizer#init\n        """\n        self.cfg = {\n            "labels": [],\n            "spans_key": spans_key,\n            "threshold": threshold,\n            "max_positive": max_positive,\n            "negative_weight": negative_weight,\n            "allow_overlap": allow_overlap,\n        }\n        self.vocab = vocab\n        self.suggester = suggester\n        self.model = model\n        self.name = name\n        self.scorer = scorer\n        self.add_negative_label = add_negative_label\n        if not allow_overlap and max_positive is not None and max_positive > 1:\n            raise ValueError(Errors.E1051.format(max_positive=max_positive))\n\n    @property\n    def key(self) -> str:\n        """Key of the doc.spans dict to save the spans under. During\n        initialization and training, the component will look for spans on the\n        reference document under the same key.\n        """\n        return str(self.cfg["spans_key"])\n\n    def _allow_extra_label(self) -> None:\n        """Raise an error if the component can not add any more labels."""\n        nO = None\n        if self.model.has_dim("nO"):\n            nO = self.model.get_dim("nO")\n        elif self.model.has_ref("output_layer") and self.model.get_ref(\n            "output_layer"\n        ).has_dim("nO"):\n            nO = self.model.get_ref("output_layer").get_dim("nO")\n        if nO is not None and nO == self._n_labels:\n            if not self.is_resizable:\n                raise ValueError(\n                    Errors.E922.format(name=self.name, nO=self.model.get_dim("nO"))\n                )\n\n    def add_label(self, label: str) -> int:\n        """Add a new label to the pipe.\n\n        label (str): The label to add.\n        RETURNS (int): 0 if label is already present, otherwise 1.\n\n        DOCS: https://spacy.io/api/spancategorizer#add_label\n        """\n        if not isinstance(label, str):\n            raise ValueError(Errors.E187)\n        if label in self.labels:\n            return 0\n        self._allow_extra_label()\n        self.cfg["labels"].append(label)  # type: ignore\n        self.vocab.strings.add(label)\n        return 1\n\n    @property\n    def labels(self) -> Tuple[str]:\n        """RETURNS (Tuple[str]): The labels currently added to the component.\n\n        DOCS: https://spacy.io/api/spancategorizer#labels\n        """\n        return tuple(self.cfg["labels"])  # type: ignore\n\n    @property\n    def label_data(self) -> List[str]:\n        """RETURNS (List[str]): Information about the component\'s labels.\n\n        DOCS: https://spacy.io/api/spancategorizer#label_data\n        """\n        return list(self.labels)\n\n    @property\n    def _label_map(self) -> Dict[str, int]:\n        """RETURNS (Dict[str, int]): The label map."""\n        return {label: i for i, label in enumerate(self.labels)}\n\n    @property\n    def _n_labels(self) -> int:\n        """RETURNS (int): Number of labels."""\n        if self.add_negative_label:\n            return len(self.labels) + 1\n        else:\n            return len(self.labels)\n\n    @property\n    def _negative_label_i(self) -> Union[int, None]:\n        """RETURNS (Union[int, None]): Index of the negative label."""\n        if self.add_negative_label:\n            return len(self.label_data)\n        else:\n            return None\n\n    def predict(self, docs: Iterable[Doc]):\n        """Apply the pipeline\'s model to a batch of docs, without modifying them.\n\n        docs (Iterable[Doc]): The documents to predict.\n        RETURNS: The models prediction for each document.\n\n        DOCS: https://spacy.io/api/spancategorizer#predict\n        """\n        indices = self.suggester(docs, ops=self.model.ops)\n        if indices.lengths.sum() == 0:\n            scores = self.model.ops.alloc2f(0, 0)\n        else:\n            scores = self.model.predict((docs, indices))  # type: ignore\n        return indices, scores\n\n    def set_candidates(\n        self, docs: Iterable[Doc], *, candidates_key: str = "candidates"\n    ) -> None:\n        """Use the spancat suggester to add a list of span candidates to a list of docs.\n        This method is intended to be used for debugging purposes.\n\n        docs (Iterable[Doc]): The documents to modify.\n        candidates_key (str): Key of the Doc.spans dict to save the candidate spans under.\n\n        DOCS: https://spacy.io/api/spancategorizer#set_candidates\n        """\n        suggester_output = self.suggester(docs, ops=self.model.ops)\n\n        for candidates, doc in zip(suggester_output, docs):  # type: ignore\n            doc.spans[candidates_key] = []\n            for index in candidates.dataXd:\n                doc.spans[candidates_key].append(doc[index[0] : index[1]])\n\n    def set_annotations(self, docs: Iterable[Doc], indices_scores) -> None:\n        """Modify a batch of Doc objects, using pre-computed scores.\n\n        docs (Iterable[Doc]): The documents to modify.\n        scores: The scores to set, produced by SpanCategorizer.predict.\n\n        DOCS: https://spacy.io/api/spancategorizer#set_annotations\n        """\n        indices, scores = indices_scores\n        offset = 0\n        for i, doc in enumerate(docs):\n            indices_i = indices[i].dataXd\n            allow_overlap = cast(bool, self.cfg["allow_overlap"])\n            if self.cfg["max_positive"] == 1:\n                doc.spans[self.key] = self._make_span_group_singlelabel(\n                    doc,\n                    indices_i,\n                    scores[offset : offset + indices.lengths[i]],\n                    allow_overlap,\n                )\n            else:\n                doc.spans[self.key] = self._make_span_group_multilabel(\n                    doc,\n                    indices_i,\n                    scores[offset : offset + indices.lengths[i]],\n                )\n            offset += indices.lengths[i]\n\n    def update(\n        self,\n        examples: Iterable[Example],\n        *,\n        drop: float = 0.0,\n        sgd: Optional[Optimizer] = None,\n        losses: Optional[Dict[str, float]] = None,\n    ) -> Dict[str, float]:\n        """Learn from a batch of documents and gold-standard information,\n        updating the pipe\'s model. Delegates to predict and get_loss.\n\n        examples (Iterable[Example]): A batch of Example objects.\n        drop (float): The dropout rate.\n        sgd (thinc.api.Optimizer): The optimizer.\n        losses (Dict[str, float]): Optional record of the loss during training.\n            Updated using the component name as the key.\n        RETURNS (Dict[str, float]): The updated losses dictionary.\n\n        DOCS: https://spacy.io/api/spancategorizer#update\n        """\n        if losses is None:\n            losses = {}\n        losses.setdefault(self.name, 0.0)\n        validate_examples(examples, "SpanCategorizer.update")\n        self._validate_categories(examples)\n        if not any(len(eg.predicted) if eg.predicted else 0 for eg in examples):\n            # Handle cases where there are no tokens in any docs.\n            return losses\n        docs = [eg.predicted for eg in examples]\n        spans = self.suggester(docs, ops=self.model.ops)\n        if spans.lengths.sum() == 0:\n            return losses\n        set_dropout_rate(self.model, drop)\n        scores, backprop_scores = self.model.begin_update((docs, spans))\n        loss, d_scores = self.get_loss(examples, (spans, scores))\n        backprop_scores(d_scores)  # type: ignore\n        if sgd is not None:\n            self.finish_update(sgd)\n        losses[self.name] += loss\n        return losses\n\n    def get_loss(\n        self, examples: Iterable[Example], spans_scores: Tuple[Ragged, Floats2d]\n    ) -> Tuple[float, float]:\n        """Find the loss and gradient of loss for the batch of documents and\n        their predicted scores.\n\n        examples (Iterable[Examples]): The batch of examples.\n        spans_scores: Scores representing the model\'s predictions.\n        RETURNS (Tuple[float, float]): The loss and the gradient.\n\n        DOCS: https://spacy.io/api/spancategorizer#get_loss\n        """\n        spans, scores = spans_scores\n        spans = Ragged(\n            self.model.ops.to_numpy(spans.data), self.model.ops.to_numpy(spans.lengths)\n        )\n        target = numpy.zeros(scores.shape, dtype=scores.dtype)\n        if self.add_negative_label:\n            negative_spans = numpy.ones((scores.shape[0]))\n        offset = 0\n        label_map = self._label_map\n        for i, eg in enumerate(examples):\n            # Map (start, end) offset of spans to the row in the d_scores array,\n            # so that we can adjust the gradient for predictions that were\n            # in the gold standard.\n            spans_index = {}\n            spans_i = spans[i].dataXd\n            for j in range(spans.lengths[i]):\n                start = int(spans_i[j, 0])  # type: ignore\n                end = int(spans_i[j, 1])  # type: ignore\n                spans_index[(start, end)] = offset + j\n            for gold_span in self._get_aligned_spans(eg):\n                key = (gold_span.start, gold_span.end)\n                if key in spans_index:\n                    row = spans_index[key]\n                    k = label_map[gold_span.label_]\n                    target[row, k] = 1.0\n                    if self.add_negative_label:\n                        # delete negative label target.\n                        negative_spans[row] = 0.0\n            # The target is a flat array for all docs. Track the position\n            # we\'re at within the flat array.\n            offset += spans.lengths[i]\n        target = self.model.ops.asarray(target, dtype="f")  # type: ignore\n        if self.add_negative_label:\n            negative_samples = numpy.nonzero(negative_spans)[0]\n            target[negative_samples, self._negative_label_i] = 1.0  # type: ignore\n        # The target will have the values 0 (for untrue predictions) or 1\n        # (for true predictions).\n        # The scores should be in the range [0, 1].\n        # If the prediction is 0.9 and it\'s true, the gradient\n        # will be -0.1 (0.9 - 1.0).\n        # If the prediction is 0.9 and it\'s false, the gradient will be\n        # 0.9 (0.9 - 0.0)\n        d_scores = scores - target\n        if self.add_negative_label:\n            neg_weight = cast(float, self.cfg["negative_weight"])\n            if neg_weight != 1.0:\n                d_scores[negative_samples] *= neg_weight\n        loss = float((d_scores**2).sum())\n        return loss, d_scores\n\n    def initialize(\n        self,\n        get_examples: Callable[[], Iterable[Example]],\n        *,\n        nlp: Optional[Language] = None,\n        labels: Optional[List[str]] = None,\n    ) -> None:\n        """Initialize the pipe for training, using a representative set\n        of data examples.\n\n        get_examples (Callable[[], Iterable[Example]]): Function that\n            returns a representative sample of gold-standard Example objects.\n        nlp (Optional[Language]): The current nlp object the component is part of.\n        labels (Optional[List[str]]): The labels to add to the component, typically generated by the\n            `init labels` command. If no labels are provided, the get_examples\n            callback is used to extract the labels from the data.\n\n        DOCS: https://spacy.io/api/spancategorizer#initialize\n        """\n        subbatch: List[Example] = []\n        if labels is not None:\n            for label in labels:\n                self.add_label(label)\n        for eg in get_examples():\n            if labels is None:\n                for span in eg.reference.spans.get(self.key, []):\n                    self.add_label(span.label_)\n            if len(subbatch) < 10:\n                subbatch.append(eg)\n        self._require_labels()\n        if subbatch:\n            docs = [eg.x for eg in subbatch]\n            spans = build_ngram_suggester(sizes=[1])(docs)\n            Y = self.model.ops.alloc2f(spans.dataXd.shape[0], self._n_labels)\n            self.model.initialize(X=(docs, spans), Y=Y)\n        else:\n            self.model.initialize()\n\n    def _validate_categories(self, examples: Iterable[Example]):\n        # TODO\n        pass\n\n    def _get_aligned_spans(self, eg: Example):\n        return eg.get_aligned_spans_y2x(\n            eg.reference.spans.get(self.key, []), allow_overlap=True\n        )\n\n    def _make_span_group_multilabel(\n        self,\n        doc: Doc,\n        indices: Ints2d,\n        scores: Floats2d,\n    ) -> SpanGroup:\n        """Find the top-k labels for each span (k=max_positive)."""\n        spans = SpanGroup(doc, name=self.key)\n        if scores.size == 0:\n            return spans\n        scores = self.model.ops.to_numpy(scores)\n        indices = self.model.ops.to_numpy(indices)\n        threshold = self.cfg["threshold"]\n        max_positive = self.cfg["max_positive"]\n\n        keeps = scores >= threshold\n        if max_positive is not None:\n            assert isinstance(max_positive, int)\n            if self.add_negative_label:\n                negative_scores = numpy.copy(scores[:, self._negative_label_i])\n                scores[:, self._negative_label_i] = -numpy.inf\n                ranked = (scores * -1).argsort()  # type: ignore\n                scores[:, self._negative_label_i] = negative_scores\n            else:\n                ranked = (scores * -1).argsort()  # type: ignore\n            span_filter = ranked[:, max_positive:]\n            for i, row in enumerate(span_filter):\n                keeps[i, row] = False\n\n        attrs_scores = []\n        for i in range(indices.shape[0]):\n            start = indices[i, 0]\n            end = indices[i, 1]\n            for j, keep in enumerate(keeps[i]):\n                if keep:\n                    if j != self._negative_label_i:\n                        spans.append(Span(doc, start, end, label=self.labels[j]))\n                        attrs_scores.append(scores[i, j])\n        spans.attrs["scores"] = numpy.array(attrs_scores)\n        return spans\n\n    def _make_span_group_singlelabel(\n        self,\n        doc: Doc,\n        indices: Ints2d,\n        scores: Floats2d,\n        allow_overlap: bool = True,\n    ) -> SpanGroup:\n        """Find the argmax label for each span."""\n        # Handle cases when there are zero suggestions\n        if scores.size == 0:\n            return SpanGroup(doc, name=self.key)\n        scores = self.model.ops.to_numpy(scores)\n        indices = self.model.ops.to_numpy(indices)\n        predicted = scores.argmax(axis=1)\n        argmax_scores = numpy.take_along_axis(\n            scores, numpy.expand_dims(predicted, 1), axis=1\n        )\n        keeps = numpy.ones(predicted.shape, dtype=bool)\n        # Remove samples where the negative label is the argmax.\n        if self.add_negative_label:\n            keeps = numpy.logical_and(keeps, predicted != self._negative_label_i)\n        # Filter samples according to threshold.\n        threshold = self.cfg["threshold"]\n        if threshold is not None:\n            keeps = numpy.logical_and(keeps, (argmax_scores >= threshold).squeeze())\n        # Sort spans according to argmax probability\n        if not allow_overlap:\n            # Get the probabilities\n            sort_idx = (argmax_scores.squeeze() * -1).argsort()\n            argmax_scores = argmax_scores[sort_idx]\n            predicted = predicted[sort_idx]\n            indices = indices[sort_idx]\n            keeps = keeps[sort_idx]\n        seen = _Intervals()\n        spans = SpanGroup(doc, name=self.key)\n        attrs_scores = []\n        for i in range(indices.shape[0]):\n            if not keeps[i]:\n                continue\n\n            label = predicted[i]\n            start = indices[i, 0]\n            end = indices[i, 1]\n\n            if not allow_overlap:\n                if (start, end) in seen:\n                    continue\n                else:\n                    seen.add(start, end)\n            attrs_scores.append(argmax_scores[i])\n            spans.append(Span(doc, start, end, label=self.labels[label]))\n\n        spans.attrs["scores"] = numpy.array(attrs_scores)\n        return spans\n',
            'spacy/tests/pipeline/test_spancat.py': 'import pytest\nimport numpy\nfrom numpy.testing import assert_array_equal, assert_almost_equal\nfrom thinc.api import get_current_ops, Ragged\n\nfrom spacy import util\nfrom spacy.lang.en import English\nfrom spacy.language import Language\nfrom spacy.tokens import SpanGroup\nfrom spacy.tokens._dict_proxies import SpanGroups\nfrom spacy.training import Example\nfrom spacy.util import fix_random_seed, registry, make_tempdir\n\nOPS = get_current_ops()\n\nSPAN_KEY = "labeled_spans"\n\nSPANCAT_COMPONENTS = ["spancat", "spancat_singlelabel"]\n\nTRAIN_DATA = [\n    ("Who is Shaka Khan?", {"spans": {SPAN_KEY: [(7, 17, "PERSON")]}}),\n    (\n        "I like London and Berlin.",\n        {"spans": {SPAN_KEY: [(7, 13, "LOC"), (18, 24, "LOC")]}},\n    ),\n]\n\nTRAIN_DATA_OVERLAPPING = [\n    ("Who is Shaka Khan?", {"spans": {SPAN_KEY: [(7, 17, "PERSON")]}}),\n    (\n        "I like London and Berlin",\n        {"spans": {SPAN_KEY: [(7, 13, "LOC"), (18, 24, "LOC"), (7, 24, "DOUBLE_LOC")]}},\n    ),\n    ("", {"spans": {SPAN_KEY: []}}),\n]\n\n\ndef make_examples(nlp, data=TRAIN_DATA):\n    train_examples = []\n    for t in data:\n        eg = Example.from_dict(nlp.make_doc(t[0]), t[1])\n        train_examples.append(eg)\n    return train_examples\n\n\n@pytest.mark.parametrize("name", SPANCAT_COMPONENTS)\ndef test_no_label(name):\n    nlp = Language()\n    nlp.add_pipe(name, config={"spans_key": SPAN_KEY})\n    with pytest.raises(ValueError):\n        nlp.initialize()\n\n\n@pytest.mark.parametrize("name", SPANCAT_COMPONENTS)\ndef test_no_resize(name):\n    nlp = Language()\n    spancat = nlp.add_pipe(name, config={"spans_key": SPAN_KEY})\n    spancat.add_label("Thing")\n    spancat.add_label("Phrase")\n    assert spancat.labels == ("Thing", "Phrase")\n    nlp.initialize()\n    assert spancat.model.get_dim("nO") == spancat._n_labels\n    # this throws an error because the spancat can\'t be resized after initialization\n    with pytest.raises(ValueError):\n        spancat.add_label("Stuff")\n\n\n@pytest.mark.parametrize("name", SPANCAT_COMPONENTS)\ndef test_implicit_labels(name):\n    nlp = Language()\n    spancat = nlp.add_pipe(name, config={"spans_key": SPAN_KEY})\n    assert len(spancat.labels) == 0\n    train_examples = make_examples(nlp)\n    nlp.initialize(get_examples=lambda: train_examples)\n    assert spancat.labels == ("PERSON", "LOC")\n\n\n@pytest.mark.parametrize("name", SPANCAT_COMPONENTS)\ndef test_explicit_labels(name):\n    nlp = Language()\n    spancat = nlp.add_pipe(name, config={"spans_key": SPAN_KEY})\n    assert len(spancat.labels) == 0\n    spancat.add_label("PERSON")\n    spancat.add_label("LOC")\n    nlp.initialize()\n    assert spancat.labels == ("PERSON", "LOC")\n\n\n# TODO figure out why this is flaky\n@pytest.mark.skip(reason="Test is unreliable for unknown reason")\ndef test_doc_gc():\n    # If the Doc object is garbage collected, the spans won\'t be functional afterwards\n    nlp = Language()\n    spancat = nlp.add_pipe("spancat", config={"spans_key": SPAN_KEY})\n    spancat.add_label("PERSON")\n    nlp.initialize()\n    texts = [\n        "Just a sentence.",\n        "I like London and Berlin",\n        "I like Berlin",\n        "I eat ham.",\n    ]\n    all_spans = [doc.spans for doc in nlp.pipe(texts)]\n    for text, spangroups in zip(texts, all_spans):\n        assert isinstance(spangroups, SpanGroups)\n        for key, spangroup in spangroups.items():\n            assert isinstance(spangroup, SpanGroup)\n            # XXX This fails with length 0 sometimes\n            assert len(spangroup) > 0\n            with pytest.raises(RuntimeError):\n                spangroup[0]\n\n\n@pytest.mark.parametrize(\n    "max_positive,nr_results", [(None, 4), (1, 2), (2, 3), (3, 4), (4, 4)]\n)\ndef test_make_spangroup_multilabel(max_positive, nr_results):\n    fix_random_seed(0)\n    nlp = Language()\n    spancat = nlp.add_pipe(\n        "spancat",\n        config={"spans_key": SPAN_KEY, "threshold": 0.5, "max_positive": max_positive},\n    )\n    doc = nlp.make_doc("Greater London")\n    ngram_suggester = registry.misc.get("spacy.ngram_suggester.v1")(sizes=[1, 2])\n    indices = ngram_suggester([doc])[0].dataXd\n    assert_array_equal(OPS.to_numpy(indices), numpy.asarray([[0, 1], [1, 2], [0, 2]]))\n    labels = ["Thing", "City", "Person", "GreatCity"]\n    for label in labels:\n        spancat.add_label(label)\n    scores = numpy.asarray(\n        [[0.2, 0.4, 0.3, 0.1], [0.1, 0.6, 0.2, 0.4], [0.8, 0.7, 0.3, 0.9]], dtype="f"\n    )\n    spangroup = spancat._make_span_group_multilabel(doc, indices, scores)\n    assert len(spangroup) == nr_results\n\n    # first span is always the second token "London"\n    assert spangroup[0].text == "London"\n    assert spangroup[0].label_ == "City"\n    assert_almost_equal(0.6, spangroup.attrs["scores"][0], 5)\n\n    # second span depends on the number of positives that were allowed\n    assert spangroup[1].text == "Greater London"\n    if max_positive == 1:\n        assert spangroup[1].label_ == "GreatCity"\n        assert_almost_equal(0.9, spangroup.attrs["scores"][1], 5)\n    else:\n        assert spangroup[1].label_ == "Thing"\n        assert_almost_equal(0.8, spangroup.attrs["scores"][1], 5)\n\n    if nr_results > 2:\n        assert spangroup[2].text == "Greater London"\n        if max_positive == 2:\n            assert spangroup[2].label_ == "GreatCity"\n            assert_almost_equal(0.9, spangroup.attrs["scores"][2], 5)\n        else:\n            assert spangroup[2].label_ == "City"\n            assert_almost_equal(0.7, spangroup.attrs["scores"][2], 5)\n\n    assert spangroup[-1].text == "Greater London"\n    assert spangroup[-1].label_ == "GreatCity"\n    assert_almost_equal(0.9, spangroup.attrs["scores"][-1], 5)\n\n\n@pytest.mark.parametrize(\n    "threshold,allow_overlap,nr_results",\n    [(0.05, True, 3), (0.05, False, 1), (0.5, True, 2), (0.5, False, 1)],\n)\ndef test_make_spangroup_singlelabel(threshold, allow_overlap, nr_results):\n    fix_random_seed(0)\n    nlp = Language()\n    spancat = nlp.add_pipe(\n        "spancat",\n        config={\n            "spans_key": SPAN_KEY,\n            "threshold": threshold,\n            "max_positive": 1,\n        },\n    )\n    doc = nlp.make_doc("Greater London")\n    ngram_suggester = registry.misc.get("spacy.ngram_suggester.v1")(sizes=[1, 2])\n    indices = ngram_suggester([doc])[0].dataXd\n    assert_array_equal(OPS.to_numpy(indices), numpy.asarray([[0, 1], [1, 2], [0, 2]]))\n    labels = ["Thing", "City", "Person", "GreatCity"]\n    for label in labels:\n        spancat.add_label(label)\n    scores = numpy.asarray(\n        [[0.2, 0.4, 0.3, 0.1], [0.1, 0.6, 0.2, 0.4], [0.8, 0.7, 0.3, 0.9]], dtype="f"\n    )\n    spangroup = spancat._make_span_group_singlelabel(\n        doc, indices, scores, allow_overlap\n    )\n    if threshold > 0.4:\n        if allow_overlap:\n            assert spangroup[0].text == "London"\n            assert spangroup[0].label_ == "City"\n            assert_almost_equal(0.6, spangroup.attrs["scores"][0], 5)\n            assert spangroup[1].text == "Greater London"\n            assert spangroup[1].label_ == "GreatCity"\n            assert spangroup.attrs["scores"][1] == 0.9\n            assert_almost_equal(0.9, spangroup.attrs["scores"][1], 5)\n        else:\n            assert spangroup[0].text == "Greater London"\n            assert spangroup[0].label_ == "GreatCity"\n            assert spangroup.attrs["scores"][0] == 0.9\n    else:\n        if allow_overlap:\n            assert spangroup[0].text == "Greater"\n            assert spangroup[0].label_ == "City"\n            assert spangroup[1].text == "London"\n            assert spangroup[1].label_ == "City"\n            assert spangroup[2].text == "Greater London"\n            assert spangroup[2].label_ == "GreatCity"\n        else:\n            assert spangroup[0].text == "Greater London"\n\n\ndef test_make_spangroup_negative_label():\n    fix_random_seed(0)\n    nlp_single = Language()\n    nlp_multi = Language()\n    spancat_single = nlp_single.add_pipe(\n        "spancat",\n        config={\n            "spans_key": SPAN_KEY,\n            "threshold": 0.1,\n            "max_positive": 1,\n        },\n    )\n    spancat_multi = nlp_multi.add_pipe(\n        "spancat",\n        config={\n            "spans_key": SPAN_KEY,\n            "threshold": 0.1,\n            "max_positive": 2,\n        },\n    )\n    spancat_single.add_negative_label = True\n    spancat_multi.add_negative_label = True\n    doc = nlp_single.make_doc("Greater London")\n    labels = ["Thing", "City", "Person", "GreatCity"]\n    for label in labels:\n        spancat_multi.add_label(label)\n        spancat_single.add_label(label)\n    ngram_suggester = registry.misc.get("spacy.ngram_suggester.v1")(sizes=[1, 2])\n    indices = ngram_suggester([doc])[0].dataXd\n    assert_array_equal(OPS.to_numpy(indices), numpy.asarray([[0, 1], [1, 2], [0, 2]]))\n    scores = numpy.asarray(\n        [\n            [0.2, 0.4, 0.3, 0.1, 0.1],\n            [0.1, 0.6, 0.2, 0.4, 0.9],\n            [0.8, 0.7, 0.3, 0.9, 0.1],\n        ],\n        dtype="f",\n    )\n    spangroup_multi = spancat_multi._make_span_group_multilabel(doc, indices, scores)\n    spangroup_single = spancat_single._make_span_group_singlelabel(doc, indices, scores)\n    assert len(spangroup_single) == 2\n    assert spangroup_single[0].text == "Greater"\n    assert spangroup_single[0].label_ == "City"\n    assert_almost_equal(0.4, spangroup_single.attrs["scores"][0], 5)\n    assert spangroup_single[1].text == "Greater London"\n    assert spangroup_single[1].label_ == "GreatCity"\n    assert spangroup_single.attrs["scores"][1] == 0.9\n    assert_almost_equal(0.9, spangroup_single.attrs["scores"][1], 5)\n\n    assert len(spangroup_multi) == 6\n    assert spangroup_multi[0].text == "Greater"\n    assert spangroup_multi[0].label_ == "City"\n    assert_almost_equal(0.4, spangroup_multi.attrs["scores"][0], 5)\n    assert spangroup_multi[1].text == "Greater"\n    assert spangroup_multi[1].label_ == "Person"\n    assert_almost_equal(0.3, spangroup_multi.attrs["scores"][1], 5)\n    assert spangroup_multi[2].text == "London"\n    assert spangroup_multi[2].label_ == "City"\n    assert_almost_equal(0.6, spangroup_multi.attrs["scores"][2], 5)\n    assert spangroup_multi[3].text == "London"\n    assert spangroup_multi[3].label_ == "GreatCity"\n    assert_almost_equal(0.4, spangroup_multi.attrs["scores"][3], 5)\n    assert spangroup_multi[4].text == "Greater London"\n    assert spangroup_multi[4].label_ == "Thing"\n    assert spangroup_multi[4].text == "Greater London"\n    assert_almost_equal(0.8, spangroup_multi.attrs["scores"][4], 5)\n    assert spangroup_multi[5].text == "Greater London"\n    assert spangroup_multi[5].label_ == "GreatCity"\n    assert_almost_equal(0.9, spangroup_multi.attrs["scores"][5], 5)\n\n\ndef test_ngram_suggester(en_tokenizer):\n    # test different n-gram lengths\n    for size in [1, 2, 3]:\n        ngram_suggester = registry.misc.get("spacy.ngram_suggester.v1")(sizes=[size])\n        docs = [\n            en_tokenizer(text)\n            for text in [\n                "a",\n                "a b",\n                "a b c",\n                "a b c d",\n                "a b c d e",\n                "a " * 100,\n            ]\n        ]\n        ngrams = ngram_suggester(docs)\n        # span sizes are correct\n        for s in ngrams.data:\n            assert s[1] - s[0] == size\n        # spans are within docs\n        offset = 0\n        for i, doc in enumerate(docs):\n            spans = ngrams.dataXd[offset : offset + ngrams.lengths[i]]\n            spans_set = set()\n            for span in spans:\n                assert 0 <= span[0] < len(doc)\n                assert 0 < span[1] <= len(doc)\n                spans_set.add((int(span[0]), int(span[1])))\n            # spans are unique\n            assert spans.shape[0] == len(spans_set)\n            offset += ngrams.lengths[i]\n        # the number of spans is correct\n        assert_array_equal(\n            OPS.to_numpy(ngrams.lengths),\n            [max(0, len(doc) - (size - 1)) for doc in docs],\n        )\n\n    # test 1-3-gram suggestions\n    ngram_suggester = registry.misc.get("spacy.ngram_suggester.v1")(sizes=[1, 2, 3])\n    docs = [\n        en_tokenizer(text) for text in ["a", "a b", "a b c", "a b c d", "a b c d e"]\n    ]\n    ngrams = ngram_suggester(docs)\n    assert_array_equal(OPS.to_numpy(ngrams.lengths), [1, 3, 6, 9, 12])\n    assert_array_equal(\n        OPS.to_numpy(ngrams.data),\n        [\n            # doc 0\n            [0, 1],\n            # doc 1\n            [0, 1],\n            [1, 2],\n            [0, 2],\n            # doc 2\n            [0, 1],\n            [1, 2],\n            [2, 3],\n            [0, 2],\n            [1, 3],\n            [0, 3],\n            # doc 3\n            [0, 1],\n            [1, 2],\n            [2, 3],\n            [3, 4],\n            [0, 2],\n            [1, 3],\n            [2, 4],\n            [0, 3],\n            [1, 4],\n            # doc 4\n            [0, 1],\n            [1, 2],\n            [2, 3],\n            [3, 4],\n            [4, 5],\n            [0, 2],\n            [1, 3],\n            [2, 4],\n            [3, 5],\n            [0, 3],\n            [1, 4],\n            [2, 5],\n        ],\n    )\n\n    # test some empty docs\n    ngram_suggester = registry.misc.get("spacy.ngram_suggester.v1")(sizes=[1])\n    docs = [en_tokenizer(text) for text in ["", "a", ""]]\n    ngrams = ngram_suggester(docs)\n    assert_array_equal(OPS.to_numpy(ngrams.lengths), [len(doc) for doc in docs])\n\n    # test all empty docs\n    ngram_suggester = registry.misc.get("spacy.ngram_suggester.v1")(sizes=[1])\n    docs = [en_tokenizer(text) for text in ["", "", ""]]\n    ngrams = ngram_suggester(docs)\n    assert_array_equal(OPS.to_numpy(ngrams.lengths), [len(doc) for doc in docs])\n\n\ndef test_ngram_sizes(en_tokenizer):\n    # test that the range suggester works well\n    size_suggester = registry.misc.get("spacy.ngram_suggester.v1")(sizes=[1, 2, 3])\n    suggester_factory = registry.misc.get("spacy.ngram_range_suggester.v1")\n    range_suggester = suggester_factory(min_size=1, max_size=3)\n    docs = [\n        en_tokenizer(text) for text in ["a", "a b", "a b c", "a b c d", "a b c d e"]\n    ]\n    ngrams_1 = size_suggester(docs)\n    ngrams_2 = range_suggester(docs)\n    assert_array_equal(OPS.to_numpy(ngrams_1.lengths), [1, 3, 6, 9, 12])\n    assert_array_equal(OPS.to_numpy(ngrams_1.lengths), OPS.to_numpy(ngrams_2.lengths))\n    assert_array_equal(OPS.to_numpy(ngrams_1.data), OPS.to_numpy(ngrams_2.data))\n\n    # one more variation\n    suggester_factory = registry.misc.get("spacy.ngram_range_suggester.v1")\n    range_suggester = suggester_factory(min_size=2, max_size=4)\n    ngrams_3 = range_suggester(docs)\n    assert_array_equal(OPS.to_numpy(ngrams_3.lengths), [0, 1, 3, 6, 9])\n\n\ndef test_overfitting_IO():\n    # Simple test to try and quickly overfit the spancat component - ensuring the ML models work correctly\n    fix_random_seed(0)\n    nlp = English()\n    spancat = nlp.add_pipe("spancat", config={"spans_key": SPAN_KEY})\n    train_examples = make_examples(nlp)\n    optimizer = nlp.initialize(get_examples=lambda: train_examples)\n    assert spancat.model.get_dim("nO") == 2\n    assert set(spancat.labels) == {"LOC", "PERSON"}\n\n    for i in range(50):\n        losses = {}\n        nlp.update(train_examples, sgd=optimizer, losses=losses)\n    assert losses["spancat"] < 0.01\n\n    # test the trained model\n    test_text = "I like London and Berlin"\n    doc = nlp(test_text)\n    assert doc.spans[spancat.key] == doc.spans[SPAN_KEY]\n    spans = doc.spans[SPAN_KEY]\n    assert len(spans) == 2\n    assert len(spans.attrs["scores"]) == 2\n    assert min(spans.attrs["scores"]) > 0.9\n    assert set([span.text for span in spans]) == {"London", "Berlin"}\n    assert set([span.label_ for span in spans]) == {"LOC"}\n\n    # Also test the results are still the same after IO\n    with make_tempdir() as tmp_dir:\n        nlp.to_disk(tmp_dir)\n        nlp2 = util.load_model_from_path(tmp_dir)\n        doc2 = nlp2(test_text)\n        spans2 = doc2.spans[SPAN_KEY]\n        assert len(spans2) == 2\n        assert len(spans2.attrs["scores"]) == 2\n        assert min(spans2.attrs["scores"]) > 0.9\n        assert set([span.text for span in spans2]) == {"London", "Berlin"}\n        assert set([span.label_ for span in spans2]) == {"LOC"}\n\n    # Test scoring\n    scores = nlp.evaluate(train_examples)\n    assert f"spans_{SPAN_KEY}_f" in scores\n    assert scores[f"spans_{SPAN_KEY}_p"] == 1.0\n    assert scores[f"spans_{SPAN_KEY}_r"] == 1.0\n    assert scores[f"spans_{SPAN_KEY}_f"] == 1.0\n\n    # also test that the spancat works for just a single entity in a sentence\n    doc = nlp("London")\n    assert len(doc.spans[spancat.key]) == 1\n\n\ndef test_overfitting_IO_overlapping():\n    # Test for overfitting on overlapping entities\n    fix_random_seed(0)\n    nlp = English()\n    spancat = nlp.add_pipe("spancat", config={"spans_key": SPAN_KEY})\n\n    train_examples = make_examples(nlp, data=TRAIN_DATA_OVERLAPPING)\n    optimizer = nlp.initialize(get_examples=lambda: train_examples)\n    assert spancat.model.get_dim("nO") == 3\n    assert set(spancat.labels) == {"PERSON", "LOC", "DOUBLE_LOC"}\n\n    for i in range(50):\n        losses = {}\n        nlp.update(train_examples, sgd=optimizer, losses=losses)\n    assert losses["spancat"] < 0.01\n\n    # test the trained model\n    test_text = "I like London and Berlin"\n    doc = nlp(test_text)\n    spans = doc.spans[SPAN_KEY]\n    assert len(spans) == 3\n    assert len(spans.attrs["scores"]) == 3\n    assert min(spans.attrs["scores"]) > 0.9\n    assert set([span.text for span in spans]) == {\n        "London",\n        "Berlin",\n        "London and Berlin",\n    }\n    assert set([span.label_ for span in spans]) == {"LOC", "DOUBLE_LOC"}\n\n    # Also test the results are still the same after IO\n    with make_tempdir() as tmp_dir:\n        nlp.to_disk(tmp_dir)\n        nlp2 = util.load_model_from_path(tmp_dir)\n        doc2 = nlp2(test_text)\n        spans2 = doc2.spans[SPAN_KEY]\n        assert len(spans2) == 3\n        assert len(spans2.attrs["scores"]) == 3\n        assert min(spans2.attrs["scores"]) > 0.9\n        assert set([span.text for span in spans2]) == {\n            "London",\n            "Berlin",\n            "London and Berlin",\n        }\n        assert set([span.label_ for span in spans2]) == {"LOC", "DOUBLE_LOC"}\n\n\n@pytest.mark.parametrize("name", SPANCAT_COMPONENTS)\ndef test_zero_suggestions(name):\n    # Test with a suggester that can return 0 suggestions\n    @registry.misc("test_mixed_zero_suggester")\n    def make_mixed_zero_suggester():\n        def mixed_zero_suggester(docs, *, ops=None):\n            if ops is None:\n                ops = get_current_ops()\n            spans = []\n            lengths = []\n            for doc in docs:\n                if len(doc) > 0 and len(doc) % 2 == 0:\n                    spans.append((0, 1))\n                    lengths.append(1)\n                else:\n                    lengths.append(0)\n            spans = ops.asarray2i(spans)\n            lengths_array = ops.asarray1i(lengths)\n            if len(spans) > 0:\n                output = Ragged(ops.xp.vstack(spans), lengths_array)\n            else:\n                output = Ragged(ops.xp.zeros((0, 0), dtype="i"), lengths_array)\n            return output\n\n        return mixed_zero_suggester\n\n    fix_random_seed(0)\n    nlp = English()\n    spancat = nlp.add_pipe(\n        name,\n        config={\n            "suggester": {"@misc": "test_mixed_zero_suggester"},\n            "spans_key": SPAN_KEY,\n        },\n    )\n    train_examples = make_examples(nlp)\n    optimizer = nlp.initialize(get_examples=lambda: train_examples)\n    assert spancat.model.get_dim("nO") == spancat._n_labels\n    assert set(spancat.labels) == {"LOC", "PERSON"}\n\n    nlp.update(train_examples, sgd=optimizer)\n    # empty doc\n    nlp("")\n    # single doc with zero suggestions\n    nlp("one")\n    # single doc with one suggestion\n    nlp("two two")\n    # batch with mixed zero/one suggestions\n    list(nlp.pipe(["one", "two two", "three three three", "", "four four four four"]))\n    # batch with no suggestions\n    list(nlp.pipe(["", "one", "three three three"]))\n\n\n@pytest.mark.parametrize("name", SPANCAT_COMPONENTS)\ndef test_set_candidates(name):\n    nlp = Language()\n    spancat = nlp.add_pipe(name, config={"spans_key": SPAN_KEY})\n    train_examples = make_examples(nlp)\n    nlp.initialize(get_examples=lambda: train_examples)\n    texts = [\n        "Just a sentence.",\n        "I like London and Berlin",\n        "I like Berlin",\n        "I eat ham.",\n    ]\n\n    docs = [nlp(text) for text in texts]\n    spancat.set_candidates(docs)\n\n    assert len(docs) == len(texts)\n    assert type(docs[0].spans["candidates"]) == SpanGroup\n    assert len(docs[0].spans["candidates"]) == 9\n    assert docs[0].spans["candidates"][0].text == "Just"\n    assert docs[0].spans["candidates"][4].text == "Just a"\n',
        }
